changeSet.sql:
UPDATE iris_session
SET course_id = (SELECT l.course_id FROM lecture l WHERE l.id = iris_session.lecture_id)
WHERE discriminator = 'LECTURE_CHAT';

UPDATE iris_session
SET discriminator = 'CHAT'
WHERE discriminator IN ('PROGRAMMING_EXERCISE_CHAT', 'TEXT_EXERCISE_CHAT', 'COURSE_CHAT', 'LECTURE_CHAT');
